import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int B = sc.nextInt(), G = sc.nextInt(), L = sc.nextInt();
            int[][] boys = new int[B][3], girls = new int[G][3];
            for (int i = 0; i < B; i++) {
                boys[i][0] = sc.nextInt();
                boys[i][1] = sc.nextInt();
                boys[i][2] = sc.nextInt();
                for (int j = 0; j < boys[i][2]; j++) {
                    sc.nextInt();
                }
            }
            for (int i = 0; i < G; i++) {
                girls[i][0] = sc.nextInt();
                girls[i][1] = sc.nextInt();
                girls[i][2] = sc.nextInt();
                for (int j = 0; j < girls[i][2]; j++) {
                    sc.nextInt();
                }
            }
            int[] pairs = new int[L + 1];
            for (int i = 0; i <= L; i++) {
                int max_pairs = 0;
                for (int j = 0; j < B; j++) {
                    if (boys[j][0] <= i && i < boys[j][1]) {
                        for (int k = 0; k < G; k++) {
                            if (girls[k][0] <= i && i < girls[k][1]) {
                                // check if boy j and girl k are interested in dancing with each other
                                max_pairs++;
                            }
                        }
                    }
                }
                pairs[i] = max_pairs;
            }
            int[] result = new int[Math.min(B, G) + 1];
            for (int i = 0; i <= L; i++) {
                result[pairs[i]]++;
            }
            for (int i = 0; i <= Math.min(B, G); i++) {
                System.out.print(result[i] + " ");
            }
            System.out.println();
        }
    }
}

